final class DemoLocationManager: NSObject, ObservableObject, CLLocationManagerDelegate {
    @Published var coordinate: CLLocationCoordinate2D?
    @Published var statusText: String = "Not started"

    private let manager = CLLocationManager()

    override init() {
        super.init()
        manager.delegate = self
        manager.desiredAccuracy = kCLLocationAccuracyBest
    }

    func start() {
        statusText = "Requesting permission"
        manager.requestWhenInUseAuthorization()
        manager.startUpdatingLocation()
    }

    func requestLocation() {
        manager.requestLocation()
    }

    func locationManagerDidChangeAuthorization(_ manager: CLLocationManager) {
        switch manager.authorizationStatus {
        case .authorizedAlways, .authorizedWhenInUse:
            statusText = "Authorized"
            manager.startUpdatingLocation()
        case .denied:
            statusText = "Denied"
        case .restricted:
            statusText = "Restricted"
        case .notDetermined:
            statusText = "Not determined"
        @unknown default:
            statusText = "Unknown"
        }
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let last = locations.last else { return }
        coordinate = last.coordinate
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        statusText = "Location error"
    }
}

struct GoogleMapView: UIViewRepresentable {
    let myLocationEnabled: Bool
    let showsMyLocationButton: Bool
    let userCoordinate: CLLocationCoordinate2D?

    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition(latitude: 37.7749, longitude: -122.4194, zoom: 12)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.settings.myLocationButton = showsMyLocationButton
        mapView.isMyLocationEnabled = myLocationEnabled
        mapView.settings.compassButton = true
        mapView.settings.rotateGestures = true
        mapView.settings.tiltGestures = true

        let marker = GMSMarker(position: CLLocationCoordinate2D(latitude: 37.7749, longitude: -122.4194))
        marker.title = "Demo Location"
        marker.snippet = "San Francisco"
        marker.map = mapView

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {
        guard let c = userCoordinate else { return }
        let update = GMSCameraUpdate.setTarget(c, zoom: max(uiView.camera.zoom, 14))
        uiView.animate(with: update)
    }
}

