final class PaymentsDemoViewModel: ObservableObject {
    @Published var statusText: String = "Ready"
    @Published var lastResultText: String?
    @Published var isPaid: Bool = false

    private var paymentSheet: PaymentSheet?
    private var clientSecret: String?

    func simulateSuccess() {
        statusText = "Paid (simulated)"
        lastResultText = "Simulated success"
        isPaid = true
    }

    func reset() {
        statusText = "Ready"
        lastResultText = nil
        isPaid = false
        paymentSheet = nil
        clientSecret = nil
    }

    @MainActor
    func presentPaymentSheet() async throws {
        statusText = "Preparing PaymentSheet…"
        if paymentSheet == nil {
            try await preparePaymentSheet()
        }
        guard let paymentSheet else {
            throw NSError(domain: "Demo", code: -1, userInfo: [NSLocalizedDescriptionKey: "PaymentSheet not ready"])
        }

        statusText = "Presenting…"
        let result = await paymentSheet.present(from: UIViewController.topMost() ?? UIViewController())
        switch result {
        case .completed:
            statusText = "Paid"
            lastResultText = "completed"
            isPaid = true
        case .canceled:
            statusText = "Canceled"
            lastResultText = "canceled"
        case .failed(let error):
            statusText = "Failed"
            lastResultText = "failed: \(error.localizedDescription)"
            throw error
        }
    }

    @MainActor
    private func preparePaymentSheet() async throws {
        // Demo-only: Use a placeholder client secret to show that app is wired.
        // For a real PaymentSheet flow, you must create a PaymentIntent on your server
        // and provide the client secret. In this demo, we allow investors to run without backend:
        // - If no valid client secret is available, we will still present a Stripe UI-less fallback.
        //
        // If you have a demo backend later, set clientSecret to your real value and remove fallback.

        if let cs = clientSecret, cs.contains("_secret_") {
            var config = PaymentSheet.Configuration()
            config.merchantDisplayName = "Demo Merchant"
            config.allowsDelayedPaymentMethods = false
            paymentSheet = PaymentSheet(paymentIntentClientSecret: cs, configuration: config)
            statusText = "PaymentSheet ready"
            return
        }

        // Fallback: Present a local demo checkout screen to keep pitch demo functional offline.
        statusText = "Offline demo mode (no backend)"
        await DemoCheckoutPresenter.presentOfflineCheckout { [weak self] outcome in
            guard let self else { return }
            switch outcome {
            case .success:
                self.statusText = "Paid (offline demo)"
                self.lastResultText = "offline-success"
                self.isPaid = true
            case .cancel:
                self.statusText = "Canceled (offline demo)"
                self.lastResultText = "offline-canceled"
            }
        }
        throw NSError(domain: "Demo", code: -2, userInfo: [NSLocalizedDescriptionKey: "No backend client secret. Used offline demo flow instead."])
    }
}

enum OfflineDemoOutcome {
    case success
    case cancel
}

enum DemoCheckoutPresenter {
    @MainActor
    static func presentOfflineCheckout(onComplete: @escaping (OfflineDemoOutcome) -> Void) async {
        guard let top = UIViewController.topMost() else {
            onComplete(.cancel)
            return
        }
        let vc = OfflineCheckoutViewController(onComplete: onComplete)
        vc.modalPresentationStyle = .pageSheet
        if let sheet = vc.sheetPresentationController {
            sheet.detents = [.medium()]
            sheet.prefersGrabberVisible = true
        }
        top.present(vc, animated: true)
    }
}

